import React, { useEffect, useRef, useState, createContext, useCallback } from "react";
import {
  Platform,
  View,
  Modal,
  StyleSheet,
  Text,
  TouchableOpacity,
  Image,
  ActivityIndicator,
} from "react-native";
import {
  useFonts,
  Montserrat_400Regular,
  Montserrat_600SemiBold,
  Montserrat_700Bold,
} from "@expo-google-fonts/montserrat";
import { NavigationContainer } from "@react-navigation/native";
import { createStackNavigator } from "@react-navigation/stack";
import { StatusBar as ExpoStatusBar } from "expo-status-bar";
import AsyncStorage from "@react-native-async-storage/async-storage";
import "./src/global.css";

// ✅ i18n (you are using these)
import { useTranslation, LanguageProvider } from "./src/i18n";

// ✅ Screens
import HomeScreen from "./src/pages/HomeScreen";

// ⛔ If you didn’t import these yet, keep them commented for now,
// otherwise React Navigation will crash and you’ll see blank.
// import OwnershipScreen from "./src/pages/OwnershipScreen";
// ... import the rest ...

export const AppContext = createContext();
const Stack = createStackNavigator();

const COLORS = {
  primary: "#024A59",
  secondary: "#D99178",
  tertiary: "#49b6d6",
  text: "#0b1a1f",
  muted: "#6B7280",
  white: "#ffffff",
  bg: "#F6FAFB",
};

// Simple safe fallback screen
function MissingScreen({ name }) {
  return (
    <View style={{ flex: 1, alignItems: "center", justifyContent: "center", padding: 18 }}>
      <Text style={{ fontSize: 18, fontWeight: "800", marginBottom: 8 }}>
        Screen missing: {name}
      </Text>
      <Text style={{ textAlign: "center", color: "#6B7280" }}>
        This route is registered but its component is undefined (not imported).
        Import the screen component or remove the route.
      </Text>
    </View>
  );
}

// Button component
const Button = ({ title, onPress, variant = "primary", style }) => {
  const buttonStyle = [
    styles.button,
    variant === "secondary" ? styles.buttonSecondary : styles.buttonPrimary,
    style,
  ];

  const textStyle = [
    styles.buttonText,
    variant === "secondary" ? styles.buttonTextSecondary : styles.buttonTextPrimary,
  ];

  return (
    <TouchableOpacity style={buttonStyle} onPress={onPress}>
      <Text style={textStyle}>{title}</Text>
    </TouchableOpacity>
  );
};

function InstallPrompt({ visible, onClose, deferredEvent }) {
  const { t } = useTranslation();
  const isIOS =
    Platform.OS === "ios" ||
    (Platform.OS === "web" && /iPad|iPhone|iPod/.test(navigator.userAgent));
  const canPrompt = !!deferredEvent;

  return (
    <Modal animationType="fade" transparent visible={visible}>
      <View style={styles.modalBackdrop}>
        <View style={styles.modalSheet}>
          <View style={{ flexDirection: "row", alignItems: "center", gap: 10, marginBottom: 6 }}>
            <Image
              source={require("./assets/icons/yellowtaxi.png")}
              style={{ width: 35, height: 35, borderRadius: 6 }}
            />
            <Text style={styles.modalTitle}>{t("install.title")}</Text>
          </View>

          {isIOS ? (
            <Text style={styles.modalText}>{t("install.iosInstructions")}</Text>
          ) : (
            <View>
              <Text style={styles.modalText}>
                {canPrompt ? t("install.promptMessage") : t("install.manualInstructions")}
              </Text>

              <Button
                title={canPrompt ? t("install.installNow") : t("common.ok")}
                onPress={() => {
                  if (deferredEvent) deferredEvent.prompt();
                  onClose();
                }}
                variant="secondary"
                style={{ marginTop: 12 }}
              />
            </View>
          )}

          <TouchableOpacity onPress={onClose} style={{ marginTop: 16, alignItems: "center" }}>
            <Text style={[styles.modalText, { color: COLORS.primary, fontWeight: "600" }]}>
              {t("install.later")}
            </Text>
          </TouchableOpacity>
        </View>
      </View>
    </Modal>
  );
}

function LoadingScreen() {
  return (
    <View style={styles.loadingContainer}>
      <ActivityIndicator size="large" color={COLORS.primary} />
      <Text style={styles.loadingText}>Chargement de votre session...</Text>
    </View>
  );
}

export default function App() {
  const [fontsLoaded] = useFonts({
    Montserrat_400Regular,
    Montserrat_600SemiBold,
    Montserrat_700Bold,
  });

  const [isLoading, setIsLoading] = useState(true);

  // ✅ Force Home for now so you SEE the screen (no blank)
  const [initialRoute] = useState("home_screen");

  const [screen, setScreen] = useState("boot");
  const [authed, setAuthed] = useState(false);
  const [profile, setProfile] = useState(null);

  const [showPrompt, setShowPrompt] = useState(false);
  const deferredPromptRef = useRef(null);

  const [driverInfo, setDriverInfo] = useState({ firstName: "", lastName: "" });
  const [ownerInfo, setOwnerInfo] = useState({
    type: null,
    firstName: "",
    lastName: "",
    organizationName: "",
    procurationFileName: "",
    idCardFileName: "",
    registreCommerceFileName: "",
  });

  const [verification, setVerification] = useState({
    verificationId: null,
    folderPrefix: null,
    numeimma: null,
    owner: null,
    driver: null,
    pendingUploads: { ownerId: null },
    documents: {
      carteGrise: [],
      carteTransport: [],
      recuImpots: [],
      licenceTransport: [],
    },
    vehicleAdmin: {
      technicalInspectionValid: null,
      technicalInspectionDate: "",
      blueCardNumber: "",
      blueCardIssueDate: "",
      ownerCatLicenseNumber: "",
      ownerCatLicenseIssueDate: "",
      municipality: "",
      municipalityTaxNumber: "",
      taxisOperated: "",
      driverPhone: "",
      driverCapacityNumber: "",
      secureBadge: null,
      driversRelayCount: "",
      macaronNumber: "",
    },
  });

  const [formProgress, setFormProgress] = useState({
    currentStep: "ownership_screen",
    completedSteps: [],
    lastSaved: null,
  });

  useEffect(() => {
    const loadSavedState = async () => {
      try {
        const [savedVerification, savedProgress, savedDriverInfo, savedOwnerInfo] =
          await Promise.all([
            AsyncStorage.getItem("verification"),
            AsyncStorage.getItem("formProgress"),
            AsyncStorage.getItem("driverInfo"),
            AsyncStorage.getItem("ownerInfo"),
          ]);

        if (savedVerification) setVerification(JSON.parse(savedVerification));
        if (savedProgress) setFormProgress(JSON.parse(savedProgress));
        if (savedDriverInfo) setDriverInfo(JSON.parse(savedDriverInfo));
        if (savedOwnerInfo) setOwnerInfo(JSON.parse(savedOwnerInfo));
      } catch (error) {
        console.error("Error loading saved state:", error);
      } finally {
        setIsLoading(false);
      }
    };

    loadSavedState();
  }, []);

  useEffect(() => {
    if (!isLoading) {
      const saveState = async () => {
        try {
          await AsyncStorage.multiSet([
            ["verification", JSON.stringify(verification)],
            ["formProgress", JSON.stringify(formProgress)],
            ["driverInfo", JSON.stringify(driverInfo)],
            ["ownerInfo", JSON.stringify(ownerInfo)],
          ]);
        } catch (error) {
          console.error("Error saving state:", error);
        }
      };
      saveState();
    }
  }, [verification, formProgress, driverInfo, ownerInfo, isLoading]);

  const go = (s) => setScreen(s);

  const clearAllData = useCallback(async () => {
    await AsyncStorage.multiRemove(["driverInfo", "ownerInfo", "verification", "formProgress"]);
    setDriverInfo({ firstName: "", lastName: "" });
    setOwnerInfo({
      type: null,
      firstName: "",
      lastName: "",
      organizationName: "",
      procurationFileName: "",
      idCardFileName: "",
      registreCommerceFileName: "",
    });
    setFormProgress({ currentStep: "ownership_screen", completedSteps: [], lastSaved: null });
    setVerification({
      verificationId: null,
      folderPrefix: null,
      numeimma: null,
      owner: null,
      driver: null,
      pendingUploads: { ownerId: null },
      documents: { carteGrise: [], carteTransport: [], recuImpots: [], licenceTransport: [] },
    });
  }, []);

  useEffect(() => {
    if (Platform.OS === "web") {
      const isStandalone =
        window.matchMedia("(display-mode: standalone)").matches ||
        navigator.standalone === true;

      let timer;
      function showSoon() {
        if (!isStandalone) setShowPrompt(true);
      }

      const onBIP = (e) => {
        e.preventDefault();
        deferredPromptRef.current = e;
        if (!isStandalone) setShowPrompt(true);
      };

      window.addEventListener("beforeinstallprompt", onBIP);
      timer = setTimeout(showSoon, 1200);

      return () => {
        window.removeEventListener("beforeinstallprompt", onBIP);
        if (timer) clearTimeout(timer);
      };
    }
  }, []);

  if (!fontsLoaded || isLoading) return <LoadingScreen />;

  return (
    <LanguageProvider>
      <AppContext.Provider
        value={{
          go,
          authed,
          setAuthed,
          profile,
          setProfile,
          driverInfo,
          setDriverInfo,
          ownerInfo,
          setOwnerInfo,
          verification,
          setVerification,
          formProgress,
          setFormProgress,
          clearAllData,
        }}
      >
        <View style={styles.container}>
          <NavigationContainer>
            <Stack.Navigator initialRouteName={initialRoute} screenOptions={{ headerShown: false }}>
              <Stack.Screen name="home_screen" component={HomeScreen} />

              {/* ✅ Keep your other screens ONLY if they are imported.
                  If any is not imported, you will get blank/crash. */}

              {/* Example safe registration (prevents blank if missing import):
              <Stack.Screen
                name="ownership_screen"
                component={OwnershipScreen || (() => <MissingScreen name="ownership_screen" />)}
              />
              */}
            </Stack.Navigator>
          </NavigationContainer>

          {Platform.OS === "web" && (
            <InstallPrompt
              visible={showPrompt}
              onClose={() => setShowPrompt(false)}
              deferredEvent={deferredPromptRef.current}
            />
          )}
        </View>
        <ExpoStatusBar style="auto" />
      </AppContext.Provider>
    </LanguageProvider>
  );
}

